// Hierarchical Bayesian model for binomial data with a Beta population prior.
// y_i ~ Binomial(n_i, theta_i)
// theta_i ~ Beta(alpha, beta)
// (alpha, beta) prior propto (alpha + beta)^(-5/2)
data {
  int<lower=0> N;              // number of observations (groups)
  array[N] int<lower=0> y;     // successes
  array[N] int<lower=0> n;     // trials
}
parameters {
  real<lower=0> alpha;                     // Beta shape parameter alpha
  real<lower=0> beta;                      // Beta shape parameter beta
  vector<lower=0, upper=1>[N] theta;       // per-group success probabilities
}
model {
  // Prior: p(alpha, beta) propto (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Population distribution of the group probabilities
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}

